import { TimeoutError } from '@danielsimonjr/workerpool';

try {
  const results = await Promise.all(
    chunks.map(chunk =>
      this.workerPool!.exec('searchEntities', [{ query, threshold, entities: chunk }])
        .timeout(30000) // 30 second timeout
    )
  );
} catch (error) {
  if (error instanceof TimeoutError) {
    console.warn('Fuzzy search timed out, falling back to single-threaded');
    return this.performFuzzyMatch(entities, queryLower, threshold);
  }
  throw error;
}

// Optional: Add cancellation support
private pendingTasks: workerpool.Promise<any>[] = [];

async cancelPendingSearches(): Promise<void> {
  for (const task of this.pendingTasks) {
    task.cancel();
  }
  this.pendingTasks = [];
}
